let lang=localStorage.cdlLang||'en',li=0,done=JSON.parse(localStorage.cdlDone||'[]'),mist=JSON.parse(localStorage.cdlMist||'[]'),deck=[],qi=0,score=0,answered=false,examSize=120,currentView='course';
const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
const T={en:{sub:'Bilingual Class A preparation',badge:'English + Spanish',hero:'Prepare harder for your CDL Class A exam.',herop:'Detailed bilingual lessons, 120 exam-style questions, mistake review, and saved progress.',start:'Start course',practice:'Practice exam',prog:'Your progress',lessons:'Lessons',questions:'Questions',route:'STUDY ROUTE',ct:'Detailed bilingual CDL course',search:'Search lessons...',lesson:'Lesson',mark:'Mark complete',completed:'✓ Completed',tip:'🧠 Memory tip',tiptext:'Say the key term in English, then explain it in your own words.',sim:'EXAM SIMULATOR',exam:'Class A practice exam',examHelp:'Choose a 50-question simulation or complete all 120 questions.',exam50:'50-question exam',exam120:'Full 120-question exam',next:'Next question →',correct:'✅ Correct',wrong:'❌ Incorrect',again:'Try again',mt:'Mistake review',empty:'No saved mistakes yet.',clear:'Clear mistakes',navCourse:'Course',navExam:'Exam',navMistakes:'Mistakes',notice:'Educational practice based on the uploaded March 2025 CDL manual and New Jersey driver manual. These are original practice questions, not leaked or guaranteed official MVC questions.'},es:{sub:'Preparación bilingüe Clase A',badge:'Inglés + español',hero:'Prepárate más fuerte para tu examen CDL Clase A.',herop:'Lecciones bilingües detalladas, 120 preguntas estilo examen, repaso de errores y progreso guardado.',start:'Empezar curso',practice:'Practicar examen',prog:'Tu progreso',lessons:'Lecciones',questions:'Preguntas',route:'RUTA DE ESTUDIO',ct:'Curso CDL bilingüe detallado',search:'Buscar lecciones...',lesson:'Lección',mark:'Marcar completada',completed:'✓ Completada',tip:'🧠 Truco para recordar',tiptext:'Pronuncia el término en inglés y luego explícalo con tus palabras.',sim:'SIMULADOR',exam:'Examen de práctica Clase A',examHelp:'Elige una simulación de 50 preguntas o completa las 120 preguntas.',exam50:'Examen de 50 preguntas',exam120:'Examen completo de 120',next:'Siguiente pregunta →',correct:'✅ Correcto',wrong:'❌ Incorrecto',again:'Intentar otra vez',mt:'Repaso de errores',empty:'Todavía no hay errores guardados.',clear:'Borrar errores',navCourse:'Curso',navExam:'Examen',navMistakes:'Errores',notice:'Práctica educativa basada en el manual CDL de marzo de 2025 y el manual de Nueva Jersey. Son preguntas originales de práctica, no preguntas filtradas ni garantizadas del MVC.'}};
const tx=k=>T[lang][k];
function ui(){for(const [id,k] of Object.entries({sub:'sub',badge:'badge',hero:'hero',herop:'herop',start:'start',practice:'practice',prog:'prog',ls:'lessons',qs:'questions',route:'route',ct:'ct',sim:'sim',exam:'exam',examHelp:'examHelp',mt:'mt',clearMistakes:'clear',navCourse:'navCourse',navExam:'navExam',navMistakes:'navMistakes',notice:'notice'}))$('#'+id).textContent=tx(k);$('#search').placeholder=tx('search');$('#lang').textContent=lang==='en'?'ES':'EN';$$('.examSize')[0].textContent=tx('exam50');$$('.examSize')[1].textContent=tx('exam120');renderList($('#search').value);renderLesson();renderMist();if(currentView==='quiz'&&deck.length)showQ(false)}
function progress(){let p=Math.round(done.length/D.lessons.length*100);$('#pct').textContent=p+'%';$('#count').textContent=done.length+' / '+D.lessons.length;$('#bar').style.width=p+'%'}
function renderList(f=''){$('#list').innerHTML='';D.lessons.forEach((l,i)=>{if(!l.title[lang].toLowerCase().includes(f.toLowerCase()))return;let b=document.createElement('button');b.className='lesson w-full rounded-2xl border border-transparent p-4 text-left '+(i===li?'active':'');b.innerHTML=`<div class="flex gap-3"><span class="text-2xl">${l.icon}</span><div class="flex-1"><small class="font-bold text-blue-700">${tx('lesson')} ${i+1}</small><b class="block">${l.title[lang]}</b></div><span>${done.includes(i)?'✅':''}</span></div>`;b.onclick=()=>{li=i;renderList($('#search').value);renderLesson()};$('#list').appendChild(b)})}
function renderLesson(){let l=D.lessons[li];$('#lb').textContent=tx('lesson')+' '+(li+1);$('#title').textContent=l.title[lang];$('#body').textContent=l[lang];$('#done').textContent=done.includes(li)?tx('completed'):tx('mark');$('#tip').textContent=tx('tip');$('#tiptext').textContent=tx('tiptext');progress()}
$('#done').onclick=()=>{done=done.includes(li)?done.filter(x=>x!==li):[...done,li];localStorage.cdlDone=JSON.stringify(done);renderList($('#search').value);renderLesson()};$('#prev').onclick=()=>{li=Math.max(0,li-1);renderList();renderLesson()};$('#next').onclick=()=>{li=Math.min(D.lessons.length-1,li+1);renderList();renderLesson()};$('#search').oninput=e=>renderList(e.target.value);
function view(v){currentView=v;$$('.view').forEach(x=>x.classList.remove('active'));$('#'+v).classList.add('active');if(v==='quiz'&&!deck.length)startQuiz(examSize);if(v==='mistakes')renderMist();scrollTo(0,0)}$$('.nav').forEach(b=>b.onclick=()=>view(b.dataset.v));
$$('.examSize').forEach(b=>b.onclick=()=>{examSize=+b.dataset.size;$$('.examSize').forEach(x=>x.className='examSize rounded-xl border px-4 py-2 font-bold');b.className='examSize rounded-xl bg-blue-700 px-4 py-2 font-bold text-white';startQuiz(examSize)});
function startQuiz(size){deck=[...D.questions].sort(()=>Math.random()-.5).slice(0,size);qi=0;score=0;answered=false;showQ(true)}
function showQ(resetAnswer=true){if(qi>=deck.length)return result();if(resetAnswer)answered=false;let q=deck[qi];if(!q._order)q._order=[0,1,2,3].sort(()=>Math.random()-.5);q._o=q._order.map(i=>q.o[lang][i]);q._a=q._order.indexOf(q.a);$('#qcount').textContent=(qi+1)+' / '+deck.length;$('#qbar').style.width=(qi/deck.length*100)+'%';$('#qbox').innerHTML=`<h3 class="text-2xl font-black">${q.q[lang]}</h3><div class="mt-6 grid gap-3">${q._o.map((o,i)=>`<button data-i="${i}" class="ans rounded-2xl border p-4 text-left font-bold">${String.fromCharCode(65+i)}. ${o}</button>`).join('')}</div><div id="fb" class="mt-5"></div>`;$$('.ans').forEach(b=>b.onclick=()=>answer(+b.dataset.i,q))}
function answer(i,q){if(answered)return;answered=true;if(i===q._a)score++;else{mist.unshift(q);mist=mist.slice(0,120);localStorage.cdlMist=JSON.stringify(mist)}$$('.ans').forEach((b,j)=>{if(j===q._a)b.classList.add('correct');if(j===i&&i!==q._a)b.classList.add('wrong')});$('#fb').innerHTML=`<div class="rounded-2xl p-5 ${i===q._a?'bg-emerald-50':'bg-red-50'}"><b>${i===q._a?tx('correct'):tx('wrong')}</b><p>${q.x[lang]}</p></div><button id="nq" class="mt-5 rounded-xl bg-blue-700 px-5 py-3 font-black text-white">${tx('next')}</button>`;$('#nq').onclick=()=>{qi++;showQ(true)}}
function result(){let total=deck.length,p=Math.round(score/total*100);$('#qcount').textContent=p+'%';$('#qbar').style.width='100%';$('#qbox').innerHTML=`<div class="py-10 text-center"><div class="text-7xl">${p>=80?'🏆':'📚'}</div><h3 class="mt-4 text-5xl font-black">${p}%</h3><p>${score} / ${total}</p><button id="again" class="mt-6 rounded-xl bg-blue-700 px-6 py-3 font-black text-white">${tx('again')}</button></div>`;$('#again').onclick=()=>startQuiz(examSize)}
function renderMist(){$('#ml').innerHTML=mist.length?mist.map(q=>`<div class="rounded-2xl border bg-white p-5"><b>${q.q[lang]}</b><p class="mt-2 font-bold text-emerald-700">${q.o[lang][q.a]}</p><p>${q.x[lang]}</p></div>`).join(''):`<div class="rounded-2xl bg-white p-8 text-center">${tx('empty')}</div>`}
$('#clearMistakes').onclick=()=>{mist=[];localStorage.cdlMist='[]';renderMist()};
$('#lang').onclick=()=>{lang=lang==='en'?'es':'en';localStorage.cdlLang=lang;ui()};ui();